<?php/** * Created by PhpStorm. * User: Cyril * Date: 01/02/2017 * Time: 08:05 */class notificationMail{    private $id_notification;    private $mail;    private $db;    private $sujet;    private $titre;    private $message;    private $envoie = true;    private $prenom_gerant;    private $nom_gerant;    private $societe;    private $mail_societe;    public function __construct($id_notification, $compte_principal='')    {        if(!$compte_principal)            $compte_principal = $_SESSION['compte_principal'];        $this->db = new MySQL();        $compte_principal = $this->db->SQLFix($compte_principal);        $this->id_notification = $this->db->SQLFix($id_notification);        $this->db->Query('SELECT COUNT(*) AS nb FROM notifications_desactivees WHERE id_notification ="'.$this->id_notification.'" AND compte_principal = "'.$compte_principal.'" ');        $row = $this->db->Row();        if($row->nb)            $this->envoie = FALSE;        else {            $sql = 'SELECT nom_societe, mail_contact, nom, prenom                               FROM comptes_principaux                               INNER JOIN staffs                              ON (staffs.compte_principal = comptes_principaux.id)                              AND (staffs.gerant = "1")                              WHERE comptes_principaux.id="' . $compte_principal . '" ';            $this->db->Query($sql);            $row = $this->db->Row();            $this->prenom_gerant = $row->prenom;            $this->nom_gerant = $row->nom;            $this->societe = $row->nom_societe;            $this->mail_societe = $row->mail_contact;            $this->mail = new Maileur();            $this->mail->addDest($row->mail_contact);            //$this->mail->addDest('contact@depaninfo67.com');            $this->db->Query('SELECT * FROM notifications_mail WHERE id="' . $this->id_notification . '"');            $row = $this->db->Row();            $this->sujet = $row->sujet;            $this->titre = $row->titre;            $this->message = nl2br($row->message);        }    }    public function tab_parse($tab)    {        if($this->envoie) {            $tab['%date%'] = date('d/m/Y à H\hi');            foreach ($tab AS $k => $v) {                $this->sujet = str_replace($k, $v, $this->sujet);                $this->titre = str_replace($k, $v, $this->titre);                if($k == '%id_inter%')                    $this->message = str_replace($k, '<a href="https://www.managy.fr/i'.$v.'">'.$v.'</a>', $this->message);                else                {                    if($k == '%client%')                    {                        $client = new GetInfosCustomer($v, true);                        $this->message = str_replace($k, '<a href="'.$client->GetProfileLink(true).'">'.$client->getFullName().'</a>', $this->message);                    }                    else                        $this->message = str_replace($k, $v, $this->message);                }                                }        }    }    private function bottomBody()    {        return '<hr />        Cet email a été envoyé par Managy pour '.$this->prenom_gerant.' '.$this->nom_gerant.' ('.$this->mail_societe.') via '.$this->societe.' le '.date('d/m/Y à H\hi').'        <br /><br />        <a href="https://www.managy.fr/admin-notifys">Cliquez-ici</a> pour gérer facilement vos paramètres de notification.';    }    public function sendMail()    {        if($this->envoie) {            $this->mail->reSetSubject('[Notification Managy] ' . $this->sujet);            $this->mail->AddTitle($this->titre);            $this->mail->body($this->message.$this->bottomBody());            $this->mail->send();        }        $this->db->Close();    }}